head.script:
/**
 * @component
 * @componentName udc_fromToYear
 * @pluginName 
 * @company 
 * @developer user
 * @category /cm/udc
 * @variableClone true
 * @notSupportBrowser 
 * @version 
 * @htmlRender 
 * @icon 
 * @disableIcon 
 * @width %
 * @height px
 * @description 
 */ 

/**
 * @property
 * @name id
 * @category 01.Basic & ETC
 * @type string
 * @option 
 * @default udc_fromToCal
 * @necessary Y
 * @description 메인화면에서 사용할 UDC ID
 */   

/**
 * @property
 * @name class
 * @category 01.Basic & ETC
 * @type string
 * @option 
 * @default 
 * @necessary N
 * @description Class ID
 */  

/**
 * @property
 * @name style
 * @category 01.Basic & ETC
 * @type string
 * @option 
 * @default 
 * @necessary N
 * @description 메안화면의 style
 */   

/**
 * @property
 * @name refStDt
 * @category 01.Basic & ETC
 * @type string
 * @option 
 * @default 
 * @necessary Y
 * @description bind 할 메인화면의  dataMap 컬럼 ID ( 시작날짜 )
 */               



/**
 * @property
 * @name refEdDt
 * @category 01.Basic & ETC
 * @type string
 * @option 
 * @default 
 * @necessary Y
 * @description bind 할 메인화면의  dataMap 컬럼 ID ( 종료날짜 )
 */            

/**
 * @property
 * @name refDataMap
 * @category 01.Basic & ETC
 * @type string
 * @option 
 * @default 
 * @necessary Y
 * @description bind 할 메인화면의 dataMap  ID (메인화면의 데이타 맵인 경우   예: ../dataMapid )
 */       

/**
 * @property
 * @name mandatoryFrom
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description From 필수입력 여부
 */

/**
 * @property
 * @name objTypeFrom
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description from 달력의 objType 속성
 */

/**
 * @property
 * @name objTypeTo
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description To 달력 objType
 */

/**
 * @property
 * @name objTypeBtn
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 달력 버튼 objTypeBtn
 */

/**
 * @property
 * @name edFromId
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description From 객체 아이디
 */

/**
 * @property
 * @name edToId
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description To 객체 아이디
 */

/**
 * @property
 * @name mandatoryTo
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description To 필수입력 여부
 */

/**
 * @property
 * @name userAuthBtn
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 버튼 userAuth 속성
 */

/**
 * @property
 * @name titleFrom
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description from 타이틀
 */

/**
 * @property
 * @name titleTo
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description to 타이틀
 */






/**
 * @method
 * @name setInit
 * @description desc
 * @return None|없음.
 * @param 
 * @hidden Y
 * @exception 
 * @sample 
 */      
	scwin.onpageload = function() {
		scwin.setInit();
		scwin.disFlag = true;
        scwin.initFlag = true; // 초기화면 셋팅시 달력도 일치하게 처리
	};

	scwin.setInit = function(){
		let opts = $p.getOptions();
		let refDataMap = opts.refDataMap;
        let pFrame = $p.parent();
        let alias, aliasId;

        if(opts.edFromId) {
            pFrame[opts.edFromId] = ipt_from;
        }
        if(opts.edToId) {
            pFrame[opts.edToId] = ipt_to;
        }

        if(opts.mandatoryFrom == "true") {
            ipt_from.setMandatory(true);
            ipt_from.options.dateValidSet = true;
        } else if(opts.mandatoryFrom == "false"){
            ipt_from.setMandatory(false);
            ipt_from.options.dateValidSet = false;
        }
        if(opts.mandatoryTo == "true") {
            ipt_to.setMandatory(true);
            ipt_to.options.dateValidSet = true;
        } else if(opts.mandatoryTo == "false"){
            ipt_to.setMandatory(false);
            ipt_to.options.dateValidSet = false;
        }
        if(opts.objTypeFrom) {
            ipt_from.options.objType = opts.objTypeFrom;
        }
        if(opts.objTypeTo) {
            ipt_to.options.objType = opts.objTypeTo;
        }
        if(opts.objTypeBtn) {
            img_Cal.options.objType = opts.objTypeBtn;
        }
        if(opts.userAuthBtn) {
            img_Cal.options.userAuth = opts.userAuthBtn;
        }

        if(opts.titleFrom) {
            ipt_from.options.invalidMessage = opts.titleFrom;
        }
        if(opts.titleTo) {
            ipt_to.options.invalidMessage = opts.titleTo;
        }

		if ( !refDataMap ) return;
        switch(pFrame[refDataMap].options.pluginName)
        {
            case "dataMap":
                alias = aliasDataMap;
                aliasId = aliasDataMap.org_id + ".";
                break;
            case "dataList":
                alias = aliasDataList;
                aliasId = aliasDataList.org_id + ".";
                break;
        }
		alias.setScope("../"+refDataMap);
		ipt_from.setRef("data:"+ aliasId + opts.refStDt);
		ipt_to.setRef("data:"+ aliasId + opts.refEdDt);
		// let refStDt = alias.get(opts.refStDt);
		// let refEdDt = alias.get(opts.refEdDt);

		// scwin.setInitDate(refStDt,refEdDt);
	};

/**
 * @method
 * @name setInitDate
 * @description desc
 * @return None|없음
 * @param <String>|fromDate|desc
 * @param <String>|toDate|desc 
 * @hidden N
 * @exception 
 * @sample 
 */    
	scwin.setInitDate = function(fromDate , toDate ){
		gr_cal.setStyle( "display" , "none" );
		scwin.disFlag = true;

		if ( fromDate.length == 4 ){
			scwin.setInitFromDate(fromDate);
		}
		if ( toDate.length == 4 ){
			scwin.setInitToDate(toDate);
		}

		cal_fr.gotoCalendar(fromDate);	
		cal_to.gotoCalendar(toDate);	

		// scwin.disableBeforeDate(fromDate);
		// scwin.disableAfterDate(toDate);
	};
/**
 * @method
 * @name setInitFromDate
 * @description desc
 * @return None|없음
 * @param <String>|dateStr|desc 
 * @hidden Y
 * @exception 
 * @sample 
 */     
	scwin.setInitFromDate = function(dateStr){
		ipt_from.setValue(dateStr);
		//scwin.setMainFromDate(dateStr);
	};

/**
 * @method
 * @name setInitToDate
 * @description desc
 * @return None|없음
 * @param <String>|dateStr|desc 
 * @hidden Y
 * @exception 
 * @sample 
 */   
	scwin.setInitToDate = function(dateStr){
		ipt_to.setValue(dateStr);
		//scwin.setMainFromDate(dateStr);
	};

/**
 * @method
 * @name setInitDate2
 * @description desc
 * @param {string} strDate desc
 * @param {string} toDate desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setInitDate2 = function (strDate, toDate) {
    gr_cal.setStyle( "display" , "none" );
    scwin.disFlag = true;

    if ( strDate.length == 4 ){
        scwin.setInitFromDate(strDate);
    }
    if ( toDate.length == 4 ){
        scwin.setInitToDate(toDate);
    }
};

	scwin.img_Cal_onclick = function(e) {
		if (scwin.disFlag){
            //$c.win.gridSettingsClose();
             gr_cal.focus();
			scwin.disFlag = false;

            let left = 0;
            if($("#"+this.id).offset().left > (560+220)) {
                left = -320 ;
            }

            let top = this.getPosition("top")+24;
            gr_cal.setStyle('top',top + 'px');		
            gr_cal.setStyle('left',left + 'px');	
            gr_cal.show("");

			if ( ipt_to.getValue()  && ipt_to.getValue().length == 4 ){
				cal_to.gotoCalendar(ipt_to.getValue());
			} else {
				cal_to.gotoCalendar($p.getCurrentServerDate( "yyyy" ));
			}
			if ( ipt_from.getValue()  && ipt_from.getValue().length == 4 ){
				cal_fr.gotoCalendar(ipt_from.getValue());
			} else {
				cal_fr.gotoCalendar($p.getCurrentServerDate( "yyyy" ));
			}
		} else {
			scwin.disFlag = true;
			gr_cal.setStyle( "display" , "none" );
		}

	};

	scwin.ipt_from_onviewchange = function(info) {
		var val = info.newValue;
		scwin.cal_fr_onyearselect (info);
	};

	scwin.ipt_to_onviewchange = function(info) {
		var val = info.newValue;
		scwin.cal_to_onyearselect (info);
	};

scwin.cal_fr_onyearselect = function (info) {//debugger;
    let dateStr = info.newValue;
    if ( dateStr >  ipt_to.getValue() && ipt_to.getValue() != "" && dateStr.length == 4){
        $c.win.alert($p,"TO DATE 보다 미래일자 입니다1.", function() {
            ipt_from.setValue("");
            cal_fr.gotoCalendar(info.oldValue);
            // ipt_from.setValue(info.oldValue);
        });
    } else {
        let minY = $W.configCacheObj.calendar.minYear || 1978;
        let maxY = $W.configCacheObj.calendar.maxYear || 2030;
        let strY = dateStr.substring(0,4);

        if(!$c.date.isDate(dateStr) && dateStr.length == 4) {
            if(parseInt(strY) < minY || parseInt(strY) > maxY) {
                $c.win.alert("날짜 형식이 올바르지 않습니다1.", function() {
                    if(gr_cal.getStyleValue("display") !== "none") {
                        ipt_from.setValue(info.oldValue);
                        cal_fr.gotoCalendar(info.oldValue);
                    } else {
                        ipt_from.setValue("");
                        ipt_from.focus();
                    }
                    return;
                });
            }
        } 

        ipt_from.setValue( dateStr );
        if ( dateStr ){
            cal_fr.gotoCalendar(dateStr);
        } else {
            cal_fr.gotoCalendar($p.getCurrentServerDate( "yyyy" ));
        }
                //cal_to.options.disableBeforeDate = dateStr;
        if ( ipt_to.getValue() ){
            scwin.disFlag = true;
            gr_cal.setStyle( "display" , "none" );
        }
    };
 	//scwin.disableBeforeDate( dateStr);	
};

scwin.cal_to_onyearselect = function (info) {
    let dateStr = info.newValue;
    if ( dateStr < ipt_from.getValue() && ipt_from.getValue() != "" && dateStr.length == 4){
        $c.win.alert($p,"FROM DATE 보다 과거일자 입니다.", function() {
            ipt_to.setValue("");
            cal_to.gotoCalendar(info.oldValue);
        });
        return;
    } else {
        let minY = $W.configCacheObj.calendar.minYear || 1978;
        let maxY = $W.configCacheObj.calendar.maxYear || 2030;
        let strY = dateStr.substring(0,4);

        if(!$c.date.isDate(dateStr) && dateStr.length == 4) {

            if(parseInt(strY) < minY || parseInt(strY) > maxY) {
                $c.win.alert("날짜 형식이 올바르지 않습니다.", function() {
                    if(gr_cal.getStyleValue("display") !== "none") {
                        ipt_to.setValue("");
                        cal_to.gotoCalendar(info.oldValue);
                    } else {
                        ipt_to.setValue("");
                        ipt_to.focus();
                    }

                    return;
                });
            }
        }

        ipt_to.setValue( dateStr );
        cal_to.gotoCalendar(dateStr);

        if ( dateStr ){
            cal_to.gotoCalendar(dateStr);
        } else {
            cal_to.gotoCalendar($p.getCurrentServerDate( "yyyy" ));
        }
        if ( ipt_from.getValue() ){
            scwin.disFlag = true;
            gr_cal.setStyle( "display" , "none" );
        }
    };
    // scwin.disableAfterDate( dateStr );
};

/**
 * @event
 * @name onBlurFrom
 * @description from blur 이벤트
 * @param {object} e desc
 * @example
 */
scwin.emit_onBlurFrom = function (e) {
	$p.emit("onBlurFrom", e);
};


/**
 * @event
 * @name onBlurTo
 * @description blurTo 이벤트
 * @param {object} e desc
 * @example
 */
scwin.emit_onBlurTo = function (e) {
	$p.emit("onBlurTo", e);
};
scwin.onBlurTo = function (e) {
    let dateStr = this.getValue(); 
    // if(this.getValue() && this.getValue().length != 4 ) {
    if(dateStr != "" && dateStr.length != 4 || (!$c.date.isDate(dateStr) && dateStr.length == 4)) {
        $c.win.alert("날짜 형식이 올바르지 않습니다.", function() {
            ipt_to.setValue("");
            ipt_to.focus();
            return;
        });
    }
    $p.emit("onBlurTo", e);
};

scwin.ipt_from_onblur = function (e) {
    let dateStr = this.getValue(); 
    // if(this.getValue() && this.getValue().length != 4 ) {
    if(dateStr != "" && dateStr.length != 4 || (!$c.date.isDate(dateStr) && dateStr.length == 4)) {
        $c.win.alert("날짜 형식이 올바르지 않습니다.", function() {
            ipt_from.setValue("");
            ipt_from.focus();
            return;
        });
    }
    $p.emit("onBlurFrom", e);
};

scwin.btn_trigger1_onclick = function (e) {
    if ( cal_fr.getDate() == "" || cal_fr.getDate().length != 4){
        $c.win.alert("시작일자를 입력하세요.", function() {
            // cal_fr.setValue("");
            cal_fr.focus();
            return;           
        });
    } else if ( cal_to.getDate() == "" || cal_to.getDate().length != 4){
        $c.win.alert("종료일자를 입력하세요.", function() {
            // cal_to.setValue("");
            cal_to.focus();
            return;           
        });
    } else if ( cal_fr.getDate() > cal_to.getDate() && cal_fr.getDate().length == 4){
        $c.win.alert("시작일자가 종료일자 이전이여야 합니다.", function() {
            // cal_fr.setValue("");
            cal_fr.focus();
            return;           
        });
    } else {
        ipt_from.setValue(cal_fr.getDate());
        ipt_to.setValue(cal_to.getDate());

        scwin.disFlag = true;
        gr_cal.setStyle( "display" , "none" );
    }
};

scwin.ipt_from_onfocus = function (e) {
    scwin.disFlag = true;
    gr_cal.setStyle( "display" , "none" );
};

scwin.ipt_to_onfocus = function (e) {
    scwin.disFlag = true;
    gr_cal.setStyle( "display" , "none" );
};
